client_script:
frappe.web_form.after_load = function() {
	frappe.call({
		method: "one_fm.api.doc_methods.user.get_my_supplier",
		callback: function(r) {
			if (r.message) {
				$('[data-fieldname="subcontractor_name"] .control-value').text(r.message);
				frappe.web_form.supplier_name = r.message;
			}
		}
	});

	let fetch_btn = $('<button class="btn btn-primary btn-sm mt-3 mb-4" id="fetch_attendance_btn">Fetch Attendance Record</button>');
	$('.frappe-control[data-fieldname="attendance_record_based_on"]').after(fetch_btn);

	frappe.web_form.on("to_date", (field, value) => {
		if (value) {
			let to_obj = frappe.datetime.str_to_obj(value);
			let allowed_date = new Date(to_obj.getFullYear(), to_obj.getMonth() + 1, 11);
			let today = frappe.datetime.str_to_obj(frappe.datetime.now_date());
			if (today < allowed_date) {
				frappe.msgprint({
					title: "Invalid Billing Month",
					indicator: "red",
					message: `You cannot select a billing month until the 10th of the following month. For ${frappe.datetime.global_date_format(value)}, you must wait until ${frappe.datetime.global_date_format(allowed_date)}.`
				});
				frappe.web_form.set_value("to_date", "");
			}
		}
	});

	fetch_btn.on('click', function(e) {
		e.preventDefault();
		let from_date = frappe.web_form.get_value("from_date");
		let to_date = frappe.web_form.get_value("to_date");
		let based_on = frappe.web_form.get_value("attendance_record_based_on");
		if (!from_date || !to_date || !based_on) {
			frappe.msgprint(__("Please fill From Date, To Date and Attendance Record Based On."));
			return;
		}
		let supplier = frappe.web_form.supplier_name;
		if (!supplier) {
			frappe.msgprint(__("Subcontractor Name not loaded yet."));
			return;
		}
		frappe.call({
			method: "one_fm.one_fm.doctype.subcontract_staff_attendance.subcontract_staff_attendance.api_fetch_subcontractor_staff",
			args: {
				subcontractor_name: supplier,
				from_date: from_date,
				to_date: to_date,
				attendance_record_based_on: based_on
			},
			callback: function(res) {
				if (res.message) {
					let grid = frappe.web_form.get_field("subcontractor_staff_attendance_item").grid;
					grid.df.data = res.message;
					grid.refresh();
					frappe.msgprint({title: "Success", message: "Attendance records fetched. You can now review and save.", indicator: "green"});
				}
			}
		});
	});

	if (frappe.web_form.doc && frappe.web_form.doc.name) {
		let state = frappe.web_form.doc.workflow_state || "Draft";

		if (state === "Draft" && !window.location.pathname.endsWith('/edit')) {
			window.location.replace(window.location.pathname + "/edit");
			return;
		}

		if (!window.location.pathname.endsWith('/edit')) {
			$('<style>.edit-button { display: none !important; }</style>').appendTo('head');
		}

		let color = state === "Draft" ? "orange" : (state === "Pending Operations Supervisor" ? "blue" : "green");
        let badge = $(`<div class="mt-2 mb-4"><span class="indicator-pill ${color}">${state}</span></div>`);
        $('.web-form-header').append(badge);

        let preview_btn = $('<button type="button" class="btn btn-outline-primary btn-sm" id="preview_attendance_btn">Preview Attendance</button>');
        $('.web-form-head .web-form-actions').append(preview_btn);
        preview_btn.on('click', function(e) {
            e.preventDefault();
            show_attendance_preview(frappe.web_form);
        });

		if (state === "Draft") {
			let submit_btn = $('<button type="button" class="btn btn-success btn-sm ml-2">Submit</button>');
			$('.web-form-actions').last().append(submit_btn);
			submit_btn.on('click', function(e) {
				e.preventDefault();
				frappe.confirm("Are you sure you want to completely submit this attendance record? Once submitted, you cannot edit it.", function() {
					frappe.call({
						method: "one_fm.api.doc_methods.user.submit_attendance",
						args: { docname: frappe.web_form.doc.name },
						callback: function(r) {
							if (!r.exc) {
								frappe.msgprint({title: "Submitted", indicator: "green", message: "Document successfully submitted."});
								setTimeout(() => { window.location.href = "/subcontractor-attendance"; }, 2000);
							}
						}
					});
				});
			});
		} else {
			$('form input, form select, form textarea, form button').not('.btn-download, #preview_attendance_btn').prop('disabled', true);
			$('.web-form-actions .btn-primary').hide();
			$('#fetch_attendance_btn').hide();
			$('.grid-add-row, .grid-remove-rows, .grid-row-check').hide();
		}
	}
};

frappe.web_form.after_save = function() {
	frappe.msgprint({
		title: __("Saved"),
		indicator: "green",
		message: __("Attendance Record has been saved successfully as Draft.")
	});
	setTimeout(function() {
		if (frappe.web_form.doc && frappe.web_form.doc.name) {
			window.location.href = "/subcontractor-attendance";
		}
	}, 1500);
};

function show_attendance_preview(web_form) {
	const doc = web_form.get_values();
	if (!doc.from_date || !doc.to_date) {
		frappe.msgprint(__("Please ensure From Date and To Date are set."));
		return;
	}
	const from_date = moment(doc.from_date);
	const to_date = moment(doc.to_date);
	const days_in_range = to_date.diff(from_date, 'days') + 1;
	const status_map = {
		"Present": "P", "Absent": "A", "On Leave": "L", "Half Day": "HD",
		"Work From Home": "WFH", "Day Off": "DO", "Client Day Off": "CDO",
		"Fingerprint Appointment": "FA", "Medical Appointment": "MA",
		"Holiday": "H", "On Hold": "OH"
	};
	let headers = `<th>${__("Employee ID")}</th><th>${__("Employee Name")}</th>`;
	let dates = [];
	for (let i = 0; i < days_in_range; i++) {
		let d = moment(from_date).add(i, 'days');
		let is_friday = d.day() === 5;
		dates.push({date: d, is_friday, day_num: d.date()});
		headers += `<th class="${is_friday ? 'bg-secondary text-white' : ''}" style="min-width:40px;text-align:center;">${d.format("D.M")}</th>`;
	}
	let rows = "";
	(doc.subcontractor_staff_attendance_item || []).forEach(row => {
		let cells = `<td>${row.employee_id || ""}</td><td>${row.employee_name || ""}</td>`;
		dates.forEach(d => {
			let val = doc.attendance_record_based_on === "Shift Hours"
				? (row[`day_${d.day_num}_hour`] || "")
				: (status_map[row[`day_${d.day_num}`]] || row[`day_${d.day_num}`] || "");
			cells += `<td class="${d.is_friday ? 'bg-light' : ''}" style="text-align:center;">${val}</td>`;
		});
		rows += `<tr>${cells}</tr>`;
	});
	const dialog = new frappe.ui.Dialog({
		title: __("Attendance Preview Matrix"),
		fields: [{
			fieldtype: "HTML",
			fieldname: "matrix_html",
			options: `<div style="overflow-x:auto;max-height:60vh;"><table class="table table-bordered table-sm" style="font-size:11px;white-space:nowrap;"><thead class="bg-light"><tr>${headers}</tr></thead><tbody>${rows}</tbody></table></div>`
		}],
		primary_action_label: __("Close"),
		primary_action: () => dialog.hide()
	});
	dialog.$wrapper.find('.modal-dialog').css('max-width', frappe.is_mobile ? '100%' : '95%');
	dialog.show();
}
